"use client";

import React, { useState, useEffect } from "react";
import { motion } from "framer-motion";
import {
  Activity,
  Server,
  Users,
  Database,
  Terminal,
  Cpu,
  ShieldAlert,
  Zap,
  Play,
  CheckCircle2,
  XCircle
} from "lucide-react";
import { pushGTMEvent } from "@/app/page";

export default function InteractiveDashboard() {
  const [activeUsers, setActiveUsers] = useState(4821);
  const [cpuLoad, setCpuLoad] = useState(32);
  const [requestsPerSec, setRequestsPerSec] = useState(840);
  const [dataPoints, setDataPoints] = useState<number[]>(Array(24).fill(50));
  const [isSimulating, setIsSimulating] = useState(false);
  const [logs, setLogs] = useState<{ id: number; text: string; type: "info" | "warn" | "error" | "success" }[]>([]);

  useEffect(() => {
    // Generowanie fa┼észywych log├│w na start
    setLogs([
      { id: 1, text: "System initialized and ready.", type: "success" },
      { id: 2, text: "Awaiting user input for simulation.", type: "info" },
    ]);
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setActiveUsers((prev) => {
        const variance = Math.floor(Math.random() * 50) - 25;
        const target = isSimulating ? 25000 : 4800;
        return Math.floor(prev + (target - prev) * 0.2 + variance);
      });

      setCpuLoad((prev) => {
        const target = isSimulating ? 95 : 30;
        const variance = Math.random() * 10 - 5;
        return Math.floor(Math.max(5, Math.min(100, prev + (target - prev) * 0.3 + variance)));
      });

      setRequestsPerSec((prev) => {
        const target = isSimulating ? 5000 : 800;
        const variance = Math.random() * 100 - 50;
        return Math.floor(Math.max(10, prev + (target - prev) * 0.3 + variance));
      });

      setDataPoints((prev) => {
        const next = [...prev.slice(1)];
        const last = next[next.length - 1];
        const target = isSimulating ? 90 : 40;
        const variance = Math.random() * 20 - 10;
        next.push(Math.max(10, Math.min(100, last + (target - last) * 0.2 + variance)));
        return next;
      });

      if (isSimulating && Math.random() > 0.6) {
        setLogs((prev) => {
          const isError = Math.random() > 0.8;
          const newLog = {
            id: Date.now(),
            text: isError ? "CRITICAL: Node latency spike > 500ms" : "WARN: High packet volume detected",
            type: isError ? "error" : ("warn" as any),
          };
          return [newLog, ...prev].slice(0, 8);
        });
      }
    }, 800);

    return () => clearInterval(interval);
  }, [isSimulating]);

  const toggleSimulation = () => {
    const nextState = !isSimulating;
    setIsSimulating(nextState);
    pushGTMEvent('symulacja_dashboard_klikniecie', { wlaczone: nextState });

    setLogs((prev) => {
      const newLog = {
        id: Date.now(),
        text: nextState ? "INITIATING STRESS TEST: Overloading servers..." : "STRESS TEST ABORTED: Systems returning to normal.",
        type: nextState ? "warn" : ("success" as any),
      };
      return [newLog, ...prev].slice(0, 8);
    });
  };

  return (
    <div className="w-full h-full flex items-center justify-center p-4 lg:p-12 relative overflow-hidden bg-transparent">
      {/* T┼éo interaktywne na czerwono je┼Ťli stres-test aktywny */}
      <motion.div
        animate={{ opacity: isSimulating ? 0.3 : 0 }}
        transition={{ duration: 1 }}
        className="absolute inset-0 bg-red-900/40 blur-[150px] pointer-events-none"
      />

      <div className="w-full max-w-6xl h-full max-h-[85vh] bg-zinc-950/90 backdrop-blur-3xl rounded-[2rem] border border-white/10 flex flex-col overflow-hidden shadow-2xl relative z-10">
        
        {/* TOP BAR */}
        <div className="h-14 border-b border-white/5 flex items-center justify-between px-6 shrink-0 bg-zinc-900/50">
          <div className="flex gap-2">
            <div className="w-3 h-3 rounded-full bg-red-500/80 shadow-[0_0_10px_rgba(239,68,68,0.5)]" />
            <div className="w-3 h-3 rounded-full bg-yellow-500/80 shadow-[0_0_10px_rgba(234,179,8,0.5)]" />
            <div className="w-3 h-3 rounded-full bg-green-500/80 shadow-[0_0_10px_rgba(34,197,94,0.5)]" />
          </div>
          <div className="font-mono text-xs text-zinc-400 tracking-widest uppercase flex items-center gap-2">
            <Activity size={14} className={isSimulating ? "text-red-500 animate-pulse" : "text-green-500"} />
            NEXUS_OS // Monitor systemu
          </div>
          <div className="flex items-center gap-2">
            <span className="relative flex h-2.5 w-2.5">
              <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${isSimulating ? 'bg-red-400' : 'bg-green-400'}`}></span>
              <span className={`relative inline-flex rounded-full h-2.5 w-2.5 ${isSimulating ? 'bg-red-500' : 'bg-green-500'}`}></span>
            </span>
            <span className={`text-[10px] font-mono tracking-widest uppercase ${isSimulating ? 'text-red-400' : 'text-green-400'}`}>
              {isSimulating ? 'Overload' : 'Stable'}
            </span>
          </div>
        </div>

        {/* MAIN CONTENT SPLIT */}
        <div className="flex flex-1 overflow-hidden flex-col md:flex-row">
          
          {/* LEFT PANEL - STATS & CONTROLS */}
          <div className="w-full md:w-1/3 border-r border-white/5 p-6 flex flex-col gap-6 overflow-y-auto">
            
            <div className="flex flex-col gap-1.5">
              <h3 className="text-white font-mono uppercase tracking-widest text-sm mb-2">Panel Kontrolny</h3>
              <p className="text-zinc-500 text-[11px] font-mono leading-relaxed mb-4">
                [Full-Stack Case Study] Interaktywny komponent testowy zbudowany za pomoc─ů React 19, Framer Motion i TailwindCSS. Odzwierciedla aplikacje typu Real-Time Dashboard.
              </p>
              
              <button
                onClick={toggleSimulation}
                className={`w-full py-4 px-6 rounded-xl font-mono text-xs font-bold tracking-widest uppercase transition-all flex items-center justify-center gap-3 relative overflow-hidden group ${
                  isSimulating 
                    ? "bg-red-500/10 text-red-500 border border-red-500/50 hover:bg-red-500/20" 
                    : "bg-orange-500/10 text-orange-500 border border-orange-500/50 hover:bg-orange-500/20"
                }`}
              >
                {isSimulating ? <XCircle size={16} /> : <Zap size={16} />}
                <span className="relative z-10">{isSimulating ? "Zatrzymaj Test" : "Stress Test"}</span>
                {!isSimulating && (
                  <motion.div 
                    animate={{ left: ["-100%", "100%"] }} 
                    transition={{ duration: 1.5, repeat: Infinity, ease: "linear" }}
                    className="absolute inset-0 w-1/2 bg-linear-to-r from-transparent via-orange-500/20 to-transparent skew-x-12"
                  />
                )}
              </button>
            </div>

            <div className="grid grid-cols-2 gap-3 mt-2">
              <StatCard title="Active Users" value={activeUsers.toLocaleString()} icon={<Users size={14} />} color={isSimulating ? "red" : "blue"} />
              <StatCard title="CPU Load" value={`${cpuLoad}%`} icon={<Cpu size={14} />} color={cpuLoad > 80 ? "red" : "green"} />
              <StatCard title="Req / Sec" value={requestsPerSec.toLocaleString()} icon={<Server size={14} />} color={isSimulating ? "orange" : "purple"} />
              <StatCard title="Database" value="99.9%" icon={<Database size={14} />} color="green" />
            </div>

            <div className="flex-1 mt-4 min-h-[150px] bg-black/50 rounded-xl border border-white/5 p-4 flex flex-col font-mono text-[10px] relative overflow-hidden">
              <div className="flex items-center gap-2 text-zinc-400 uppercase tracking-widest mb-3 pb-2 border-b border-white/5">
                <Terminal size={12} /> Live Logs
              </div>
              <div className="flex flex-col gap-2 overflow-y-auto">
                {logs.map((log) => (
                  <motion.div 
                    initial={{ opacity: 0, x: -10 }} 
                    animate={{ opacity: 1, x: 0 }} 
                    key={log.id} 
                    className={`flex gap-2 items-start ${
                      log.type === "error" ? "text-red-400" :
                      log.type === "warn" ? "text-orange-400" :
                      log.type === "success" ? "text-green-400" : "text-blue-400"
                    }`}
                  >
                    <span className="opacity-50 shrink-0">[{new Date(log.id).toISOString().split('T')[1].slice(0, 8)}]</span>
                    <span>{log.text}</span>
                  </motion.div>
                ))}
              </div>
            </div>
            
          </div>

          {/* RIGHT PANEL - DATA VISUALIZATION */}
          <div className="w-full md:w-2/3 p-6 flex flex-col relative overflow-hidden">
            <div className="absolute inset-0 bg-[linear-gradient(to_right,#ffffff05_1px,transparent_1px),linear-gradient(to_bottom,#ffffff05_1px,transparent_1px)] bg-size-[20px_20px] pointer-events-none" />
            
            <div className="flex justify-between items-center mb-8 relative z-10">
              <h3 className="font-mono text-xs uppercase tracking-widest text-zinc-400">Sie─ç / Przepustowo┼Ť─ç</h3>
              <div className="px-3 py-1 rounded-full bg-zinc-900 border border-white/5 font-mono text-[9px] text-zinc-500 uppercase">
                Ostatnie 24 sekundy
              </div>
            </div>

            <div className="flex-1 relative z-10 flex items-end justify-between gap-1 sm:gap-2 pt-10">
              {dataPoints.map((val, i) => {
                const heightPercentage = `${val}%`;
                const isHigh = val > 80;
                return (
                  <div key={i} className="relative flex-1 bg-white/5 rounded-t-sm flex items-end justify-center group h-full">
                    <motion.div 
                      layout
                      animate={{ height: heightPercentage }}
                      transition={{ type: "spring", stiffness: 300, damping: 20 }}
                      className={`w-full rounded-t-sm opacity-80 group-hover:opacity-100 transition-opacity ${
                        isSimulating 
                          ? (isHigh ? "bg-red-500 shadow-[0_0_15px_#ef4444]" : "bg-orange-500") 
                          : "bg-blue-500 shadow-[0_0_10px_#3b82f6]"
                      }`}
                    />
                    {/* Tooltip */}
                    <div className="absolute -top-8 bg-zinc-800 text-white font-mono text-[9px] px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap z-50">
                      {val.toFixed(0)} Mbps
                    </div>
                  </div>
                );
              })}
            </div>

            {/* FAKE MAP/NODES OVERLAY BEHIND CHART */}
            <div className="absolute inset-0 z-0 flex items-center justify-center opacity-10 pointer-events-none">
                <svg className="w-full h-full max-h-[300px]" viewBox="0 0 100 100" preserveAspectRatio="none">
                  {[...Array(10)].map((_, i) => (
                    <circle key={i} cx={Math.random() * 100} cy={Math.random() * 100} r="1" fill="currentColor" className="animate-pulse text-white" />
                  ))}
                  {[...Array(15)].map((_, i) => (
                    <path key={`p${i}`} d={`M${Math.random()*100},${Math.random()*100} L${Math.random()*100},${Math.random()*100}`} stroke="currentColor" strokeWidth="0.1" strokeDasharray="1,1" className="text-zinc-500" />
                  ))}
                </svg>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
}

function StatCard({ title, value, icon, color }: { title: string, value: string, icon: React.ReactNode, color: string }) {
  const colorMap: Record<string, string> = {
    red: "text-red-400 bg-red-400/10 border-red-400/20",
    green: "text-green-400 bg-green-400/10 border-green-400/20",
    blue: "text-blue-400 bg-blue-400/10 border-blue-400/20",
    orange: "text-orange-400 bg-orange-400/10 border-orange-400/20",
    purple: "text-purple-400 bg-purple-400/10 border-purple-400/20",
  };

  return (
    <div className="bg-zinc-900/50 border border-white/5 rounded-xl p-3 flex flex-col gap-2">
      <div className={`w-6 h-6 rounded-md flex items-center justify-center border ${colorMap[color] || colorMap.blue}`}>
        {icon}
      </div>
      <div className="font-mono text-[9px] text-zinc-500 uppercase tracking-widest mt-1">{title}</div>
      <div className="text-base sm:text-lg font-bold text-white tracking-tight">{value}</div>
    </div>
  );
}
